			Actor:     assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
	}
	if noChanges.Label != "" {
		if lerr := addBeadLabel(w.Store, candidate.ID, noChanges.Label); lerr != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "addBeadLabel", lerr, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
	}
	if noChanges.Satisfied {
		// Adjudication confirmed bead is already satisfied.
		// Set the terminal status BEFORE the close so the late
		// executeBeadLoopEvent append captures "already_satisfied"
		// (not "no_changes"), and emit an early execute-bead
		// evidence event so the closure gate accepts even when
		// BaseRev is empty (test fixtures and genuinely-no-commit
		// satisfied beads).
		report.Status = ExecuteBeadStatusAlreadySatisfied
		if noChanges.Evidence != "" {
			// Checker evidence explains why the bead is being closed;
			// it takes precedence over the executor's attempt detail.
			report.Detail = noChanges.Evidence
		}
		_ = w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC()))
		if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.BaseRev); cerr != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "CloseWithEvidence", cerr, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		result.Successes++
		result.LastSuccessAt = now().UTC()
	} else {
		// Unresolved: suppress immediate retry so the queue can
		// move on to other beads.
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		if shouldSuppressNoProgress(report) {
			retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
			if cerr := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); cerr != nil {
				if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", cerr, assignee, result, runtime, now) {
					continue
				}
				return result, ctx.Err()
			}
			report.RetryAfter = retryAfter.Format(time.RFC3339)
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	}
} else {
	if attemptOut.Parking == nil && attemptOut.Disposition != agenttry.OutcomePark {
		if err := w.Store.Unclaim(candidate.ID); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "Unclaim", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
	}
	if report.Status == ExecuteBeadStatusPreservedNeedsReview {
		if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "AppendNotes", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	} else {
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		if shouldSuppressNoProgress(report) {
			retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
			if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
				if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", err, assignee, result, runtime, now) {
					continue
				}
				return result, ctx.Err()
			}
			report.RetryAfter = retryAfter.Format(time.RFC3339)
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	}
}

result.Results = append(result.Results, report)

// Skip the late execute-bead append for already-satisfied beads —
// the satisfied path appends its own terminal event before
// CloseWithEvidence so the closure gate sees execution evidence.
// Duplicating it here would yield two identical events.
if report.Status != ExecuteBeadStatusAlreadySatisfied {
	if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
		// Event recording failure is non-terminal: log it and continue.
		// result counters were already updated by the outcome block above;
		// do not double-count by calling handleOutcomeStoreError.
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
		}
		if ctx.Err() == nil {
			_ = w.Store.SetExecutionCooldown(candidate.ID, now().UTC().Add(StoreErrorCooldown), "loop-error", "AppendEvent: "+err.Error())
		}
		if ctx.Err() != nil {
			return result, ctx.Err()
		}
		continue
	}
}

// Emit terminal progress phase event.
terminalPhase := "failed"
if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
	terminalPhase = "done"
} else if report.PreserveRef != "" {
	terminalPhase = "preserved"
}
// Use the real attempt_id from the report if available.
finalAttemptID := report.AttemptID
if finalAttemptID == "" {
	finalAttemptID = provAttemptID
}
phaseSeq++
emitProgress(runtime.ProgressCh, ProgressEvent{
	EventID:   "evt-" + randomProgressID(),

				ResultRev: "feed1234",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		// No Once flag: loop runs until no more candidates.
		PreClaimHook: func(ctx context.Context) error {
			hookCalls++
			if hookCalls == 1 {
				return fmt.Errorf("diverged branch on first hook call")
			}
			return nil
		},
	})
	require.NoError(t, err)
	// The bead was skipped once (hook fail), then retried and succeeded.
	assert.Equal(t, 1, result.Attempts, "bead should be executed exactly once after hook passes")
	assert.Equal(t, 1, result.Successes)
	assert.Equal(t, []string{b.ID}, executedIDs)

	got, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status)
}

// TestExecuteBeadWorkerStoreErrorContinuesLoop verifies root cause #2: any
// Store.* error in the post-Execute outcome block must NOT terminate the loop.
// The loop must: continue to the next iteration, record a kind:loop-error event
// on the affected bead, and increment result.Failures.
//
// Regression for ddx-37cdb43a.
func TestExecuteBeadWorkerStoreErrorContinuesLoop(t *testing.T) {
	injectedErr := fmt.Errorf("transient storage failure")

	cases := []struct {
		name           string
		executorStatus string
		injectErr      func(s *errorInjectingStore)
		wantOp         string
	}{
		{
			name:           "Unclaim fails on no_changes path",
			executorStatus: ExecuteBeadStatusNoChanges,
			injectErr: func(s *errorInjectingStore) {
				s.onUnclaim = func(id string) error { return injectedErr }
			},
			wantOp: "Unclaim",
		},
		{
			name:           "IncrNoChangesCount fails",
			executorStatus: ExecuteBeadStatusNoChanges,
			injectErr: func(s *errorInjectingStore) {
				s.onIncrNoChanges = func(id string) (int, error) { return 0, injectedErr }
			},
			wantOp: "IncrNoChangesCount",
		},
		{
			name:           "adjudicateNoChanges fails via SatisfactionChecker",
			executorStatus: ExecuteBeadStatusNoChanges,
			injectErr:      nil, // injected via SatisfactionChecker, not store
			wantOp:         "adjudicateNoChanges",
		},
		{
			name:           "CloseWithEvidence fails on success path",
			executorStatus: ExecuteBeadStatusSuccess,
			injectErr: func(s *errorInjectingStore) {
				s.onCloseWithEvidence = func(id, sessionID, commitSHA string) error { return injectedErr }
			},
			wantOp: "CloseWithEvidence",
		},
		{
			name:           "SetExecutionCooldown fails on no_changes no-progress path",
			executorStatus: ExecuteBeadStatusNoChanges,
			injectErr: func(s *errorInjectingStore) {
				s.onSetCooldown = func(id string, until time.Time, status, detail string) error { return injectedErr }
			},
			wantOp: "SetExecutionCooldown",
		},
		{
			name:           "SetExecutionCooldown fails on execution_failed path",
			executorStatus: ExecuteBeadStatusExecutionFailed,
			injectErr: func(s *errorInjectingStore) {
				// execution_failed doesn't call SetExecutionCooldown unless
				// shouldSuppressNoProgress — use a report with matching base/result rev.
				// Actually execution_failed goes through the else branch which
				// calls SetExecutionCooldown only if shouldSuppressNoProgress.
				// To trigger it, inject at the Unclaim level so we get to that branch.
				s.onUnclaim = func(id string) error { return injectedErr }
			},
			wantOp: "Unclaim",
		},
		{
			name:           "late AppendEvent fails",
			executorStatus: ExecuteBeadStatusExecutionFailed,
			injectErr: func(s *errorInjectingStore) {
				callCount := 0
				s.onAppendEvent = func(id string, event bead.BeadEvent) error {
					callCount++
					// Fail only the late execute-bead event (not loop-error events).
					if event.Kind == "execute-bead" || event.Kind == "" {
						return injectedErr
					}
					return nil
				}
			},
			wantOp: "AppendEvent",
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			realStore := bead.NewStore(t.TempDir())
			require.NoError(t, realStore.Init())

			// Two beads: first gets the error injection, second should still be processed.
			first := &bead.Bead{ID: "ddx-err-first", Title: "First bead"}
			second := &bead.Bead{ID: "ddx-err-second", Title: "Second bead"}
			require.NoError(t, realStore.Create(first))
			require.NoError(t, realStore.Create(second))

			store := &errorInjectingStore{ExecuteBeadLoopStore: realStore}
			if tc.injectErr != nil {
				tc.injectErr(store)
			}

			// For the adjudicateNoChanges case, inject via SatisfactionChecker.
			var satisfactionChecker SatisfactionChecker
			if tc.wantOp == "adjudicateNoChanges" {
				satisfactionChecker = satisfactionCheckerFunc(func(ctx context.Context, beadID string, noChangesCount int) (bool, string, error) {
					if beadID == first.ID {
						return false, "", injectedErr
					}
					return false, "", nil
				})
			}

			var executedIDs []string
			worker := &ExecuteBeadWorker{
				Store:               store,
				SatisfactionChecker: satisfactionChecker,
				Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
					executedIDs = append(executedIDs, beadID)
					status := tc.executorStatus
					if beadID == second.ID {
						status = ExecuteBeadStatusSuccess
					}
					return ExecuteBeadReport{
						BeadID:    beadID,
						Status:    status,
						SessionID: "sess-" + beadID,
						ResultRev: "rev-" + beadID,
						BaseRev:   "rev-" + beadID, // same as ResultRev → triggers shouldSuppressNoProgress
					}, nil
				}),
			}

			cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
			rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
			result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{})
			require.NoError(t, err, "loop must not return error on store failure")

			// (a) loop continues — second bead must have been executed.
			assert.Contains(t, executedIDs, second.ID, "loop must continue to next bead after store error on first")

			// (c) result.Failures advances.
			assert.GreaterOrEqual(t, result.Failures, 1, "result.Failures must be >= 1 after store error")

			// (b) kind:loop-error event recorded on the affected bead (best-effort;
			// not checked for AppendEvent failures since the event sink itself is broken).
			if tc.wantOp != "AppendEvent" {
				events, evErr := realStore.Events(first.ID)
				require.NoError(t, evErr)
				var loopErrorEvent *bead.BeadEvent
				for i := range events {
					if events[i].Kind == "loop-error" {
						loopErrorEvent = &events[i]
						break
					}
				}
				require.NotNil(t, loopErrorEvent, "kind:loop-error event must be recorded; got events: %v", events)
				assert.Contains(t, loopErrorEvent.Summary, tc.wantOp,
					"loop-error summary must contain the failing operation name")
			}
		})
	}
}

// TestExecuteBeadWorkerEndToEndThreeBeadDrain is the integration guard from
// AC-4: seeds 3 ready beads with outcomes no_changes / success /
// already_satisfied and asserts all three are processed without premature exit.
// With the pre-fix loop this test failed because the no_changes result caused
// Unclaim to be the first store call and the loop exited on any transient path.
func TestExecuteBeadWorkerEndToEndThreeBeadDrain(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	a := &bead.Bead{ID: "ddx-e2e-a", Title: "Bead A — no_changes", Priority: 0}
	b := &bead.Bead{ID: "ddx-e2e-b", Title: "Bead B — success", Priority: 1}
	c := &bead.Bead{ID: "ddx-e2e-c", Title: "Bead C — already_satisfied", Priority: 2}
	require.NoError(t, store.Create(a))
	require.NoError(t, store.Create(b))
	require.NoError(t, store.Create(c))

	var executedIDs []string
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			executedIDs = append(executedIDs, beadID)
			switch beadID {
			case a.ID:
				return ExecuteBeadReport{
					BeadID:    beadID,
					Status:    ExecuteBeadStatusNoChanges,
					BaseRev:   "aaa",
					ResultRev: "aaa", // equal → shouldSuppressNoProgress
				}, nil
			case b.ID:
				return ExecuteBeadReport{
					BeadID:    beadID,
					Status:    ExecuteBeadStatusSuccess,
					SessionID: "sess-b",
					ResultRev: "bbb",
				}, nil
			case c.ID:
				// Returning no_changes with a verification_command that exits 0
				// (NoChangesContract verified path) closes the bead as
				// already_satisfied on the first attempt.
				return ExecuteBeadReport{
					BeadID:             beadID,
					Status:             ExecuteBeadStatusNoChanges,
					BaseRev:            "ccc",
					ResultRev:          "ccc",
					NoChangesRationale: "verification_command: true\noutput: passes",
				}, nil
			default:
				return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess}, nil
			}
		}),
		VerificationRunner: func(ctx context.Context, projectRoot, command string) (int, string, error) {
			return 0, "", nil
		},

package agent

import (
	"encoding/json"
	"fmt"
	"os"
	"strings"
)

// ExecuteBeadIterationBlock is the machine-readable JSON payload embedded in
// execute-bead iteration commit messages as the "ddx-iteration:" trailer value.
// All fields are projected from result.json; the struct is the canonical source
// for both commit-message rendering and forward-compatibility testing.
type ExecuteBeadIterationBlock struct {
	BeadID              string  `json:"bead_id"`
	AttemptID           string  `json:"attempt_id"`
	SessionID           string  `json:"session_id,omitempty"`
	Harness             string  `json:"harness,omitempty"`
	Provider            string  `json:"provider,omitempty"`
	Model               string  `json:"model,omitempty"`
	TotalTokens         int     `json:"total_tokens"`
	CostUSD             float64 `json:"cost_usd"`
	BaseRev             string  `json:"base_rev"`
	ResultRev           string  `json:"result_rev,omitempty"`
	RequiredExecSummary string  `json:"required_exec_summary"`
	Outcome             string  `json:"outcome"`
	ExecutionBundle     string  `json:"execution_bundle"`
}

// BuildIterationCommitMessage renders the canonical execute-bead iteration
// commit message from res. All values are projected from the result — the same
// fields that are written to result.json — so the message is re-derivable from
// the tracked artifact file without re-running the agent.
//
// The message includes:
//   - A structured subject line referencing the bead ID
//   - The ddx-iteration JSON block (compact agent/provider metadata)
//   - The canonical Git trailer set (Ddx-Attempt-Id, Ddx-Worker-Id,
//     Ddx-Harness, Ddx-Model, Ddx-Result-Status)
//
// Unknown fields are handled deterministically: ResultRev is omitted when
// empty; RequiredExecSummary defaults to "skipped" when unset; WorkerID falls
// back to SessionID when no distinct worker identity exists.
func BuildIterationCommitMessage(res *ExecuteBeadResult) string {
	block := ExecuteBeadIterationBlock{
		BeadID:              res.BeadID,
		AttemptID:           res.AttemptID,
		SessionID:           res.SessionID,
		Harness:             res.Harness,
		Provider:            res.Provider,
		Model:               res.Model,
		TotalTokens:         res.Tokens,
		CostUSD:             res.CostUSD,
		BaseRev:             res.BaseRev,
		ResultRev:           res.ResultRev,
		RequiredExecSummary: iterationRequiredExecSummary(res),
		Outcome:             res.Outcome,
		ExecutionBundle:     res.ExecutionDir,
	}

	blockJSON, err := json.MarshalIndent(block, "", "  ")
	if err != nil {
		// Fallback: minimal inline block so the commit is never trailer-free.
		blockJSON = []byte(fmt.Sprintf(`{"bead_id":%q,"attempt_id":%q}`, res.BeadID, res.AttemptID))
	}

	// Ddx-Worker-Id falls back to SessionID when no distinct worker identity exists.
	workerID := res.WorkerID
	if workerID == "" {
		workerID = res.SessionID
	}

	var b strings.Builder
	b.WriteString("chore: execute-bead iteration ")
	b.WriteString(res.BeadID)
	b.WriteString("\n\nddx-iteration: ")
	b.WriteString(string(blockJSON))
	// Blank line between the JSON block and the canonical trailer set is required
	// by git-interpret-trailers so that the trailers are parsed correctly.
	b.WriteString("\n\nDdx-Attempt-Id: ")
	b.WriteString(res.AttemptID)
	b.WriteString("\nDdx-Worker-Id: ")
	b.WriteString(workerID)
	b.WriteString("\nDdx-Harness: ")
	b.WriteString(res.Harness)
	b.WriteString("\nDdx-Model: ")
	b.WriteString(res.Model)
	b.WriteString("\nDdx-Result-Status: ")
	b.WriteString(res.Status)
	return b.String()
}

// iterationRequiredExecSummary returns the required_exec_summary value for the
// ddx-iteration block. When the orchestrator has not yet evaluated gates (i.e.
// the preliminary result is written before the synthesized commit), the field
// defaults to "skipped" per the documented contract. After ApplyLandingToResult
// the field is populated with the real summary and the final result.json is
// written.
func iterationRequiredExecSummary(res *ExecuteBeadResult) string {
	if res.RequiredExecSummary != "" {
		return res.RequiredExecSummary
	}
	return "skipped"
}

// BuildCommitMessageFromResultFile reads the result.json artifact at resultPath
// and renders the canonical execute-bead iteration commit message from it.
// This is the file-sourced rendering path: callers must write result.json before
// calling this function. The message is deterministic for a given result.json —
// anyone can re-derive it from the tracked bundle without re-running the agent.
func BuildCommitMessageFromResultFile(resultPath string) (string, error) {
	raw, err := os.ReadFile(resultPath)
	if err != nil {
		return "", fmt.Errorf("reading result file %s: %w", resultPath, err)
	}
	var res ExecuteBeadResult
	if err := json.Unmarshal(raw, &res); err != nil {
		return "", fmt.Errorf("parsing result file %s: %w", resultPath, err)
	}
	return BuildIterationCommitMessage(&res), nil
}

