160	// handleOutcomeStoreError is called when a Store.* operation in the
161	// post-Execute outcome block returns a non-nil error. It logs the error,
162	// appends a kind:loop-error event to the bead (best-effort), sets a short
163	// cooldown so the bead is not immediately re-queued, increments
164	// result.Failures, and returns true — signalling the caller to continue to
165	// the next loop iteration rather than returning.
166	//
167	// If ctx is already cancelled, it returns false so the caller can propagate
168	// the cancellation immediately.
169	func (w *ExecuteBeadWorker) handleOutcomeStoreError(ctx context.Context, beadID, operation string, storeErr error, assignee string, result *ExecuteBeadLoopResult, runtime ExecuteBeadLoopRuntime, now func() time.Time) bool {
170		if ctx.Err() != nil {
171			return false
172		}
173		if runtime.Log != nil {
174			_, _ = fmt.Fprintf(runtime.Log, "outcome store error (%s %s): %v (continuing)\n", operation, beadID, storeErr)
175		}
176		_ = w.Store.AppendEvent(beadID, bead.BeadEvent{
177			Kind:      "loop-error",
178			Summary:   operation + " failed",
179			Body:      storeErr.Error(),
180			Actor:     assignee,
181			Source:    "ddx agent execute-loop",
182			CreatedAt: now().UTC(),
183		})
184		cooldownUntil := now().UTC().Add(StoreErrorCooldown)
185		_ = w.Store.SetExecutionCooldown(beadID, cooldownUntil, "loop-error", operation+": "+storeErr.Error())
186		result.Failures++
187		result.LastFailureStatus = "loop-error"
188		return true
189	}
